const channel = new BroadcastChannel('app:leader');
const id = Math.random().toString(36).slice(2);
let isLeader = false;
const listeners = new Set<(leader: boolean) => void>();

function broadcast(type: string, data: Record<string, unknown> = {}) { channel.postMessage({ type, id, ...data, at: Date.now() }); }

channel.onmessage = (e) => {
  if (e.data.type === 'hello' && e.data.id < id) { setLeader(false); }
  if (e.data.type === 'claim' && e.data.id < id) { setLeader(false); }
};

function setLeader(v: boolean) { if (isLeader === v) return; isLeader = v; for (const l of listeners) l(v); }

export function startLeaderElection() {
  broadcast('hello');
  setTimeout(() => { if (!isLeader) setLeader(true); broadcast('claim'); }, 200);
  document.addEventListener('visibilitychange', () => { if (document.hidden && isLeader) setLeader(false); else if (!document.hidden) { broadcast('claim'); setTimeout(() => setLeader(true), 200); } });
}

export function onLeader(l: (leader: boolean) => void) { listeners.add(l); l(isLeader); return () => listeners.delete(l); }
export function getIsLeader() { return isLeader; }

