import cronParser from 'cron-parser';
import { ReportDefinitionModel } from '../models/report-definition.model';
import { getTemplate } from '../reports/registry';
import { enqueue } from '../queue/enqueue';

export async function runDueReports() {
  const defs = await ReportDefinitionModel.find({});
  const now = new Date();
  for (const def of defs) {
    try {
      const it = cronParser.parseExpression(def.cron, { tz: def.timezone, currentDate: def.lastRunAt ?? new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000) });
      const next = it.next().toDate();
      if (next > now) continue;
      const template = getTemplate(def.templateId);
      if (!template) throw new Error('TEMPLATE_NOT_FOUND');
      const params = template.paramsSchema.parse(def.params ?? {});
      const result = await template.run(params as Record<string, unknown>, String(def.orgId));
      for (const recipient of def.recipients) await enqueue.email({ to: recipient, template: 'report', data: { result } });
      def.lastRunAt = now; def.lastError = ''; await def.save();
    } catch (e) { def.lastError = (e as Error).message; await def.save(); }
  }
}

