export function renderSafe(template: string, vars: Record<string, unknown>): string {
  if (template.length > 50_000) throw new Error('TEMPLATE_TOO_LARGE');
  if (/{{>\s/.test(template)) throw new Error('PARTIALS_NOT_ALLOWED');
  if (/{{\s*#with\s/.test(template)) throw new Error('WITH_NOT_ALLOWED');
  const compiled = safe.compile(template, { strict: true, noEscape: false });
  return compiled(vars);
}

