import * as THREE from 'three';
import { createNoise2D } from 'simplex-noise';

const noise = createNoise2D();

export function buildChunk(cx: number, cz: number, size: number, segments: number): THREE.Mesh {
  const geo = new THREE.PlaneGeometry(size, size, segments, segments);
  geo.rotateX(-Math.PI / 2);
  const pos = geo.attributes.position;
  for (let i = 0; i < pos.count; i++) {
    const wx = pos.getX(i) + cx * size;
    const wz = pos.getZ(i) + cz * size;
    pos.setY(i, noise(wx * 0.02, wz * 0.02) * 4 + noise(wx * 0.08, wz * 0.08) * 1);
  }
  pos.needsUpdate = true;
  geo.computeVertexNormals();
  const mat = new THREE.MeshStandardMaterial({ color: '#7c8c5a' });
  const mesh = new THREE.Mesh(geo, mat);
  mesh.position.set(cx * size, 0, cz * size);
  return mesh;
}

import { Canvas, useThree, useFrame } from '@react-three/fiber';
import { OrbitControls } from '@react-three/drei';
import { useEffect, useRef } from 'react';
import * as THREE from 'three';
import { buildChunk } from './TerrainChunk';

const SIZE = 32;
const NEAR_LOD = 32;
const FAR_LOD = 8;
const RADIUS = 5;

function ChunkManager() {
  const { camera, scene } = useThree();
  const chunks = useRef(new Map<string, { mesh: THREE.Mesh; lod: number }>());
  useFrame(() => {
    const cx0 = Math.floor(camera.position.x / SIZE);
    const cz0 = Math.floor(camera.position.z / SIZE);
    const needed = new Set<string>();
    for (let dx = -RADIUS; dx <= RADIUS; dx++) for (let dz = -RADIUS; dz <= RADIUS; dz++) {
      const cx = cx0 + dx; const cz = cz0 + dz;
      const key = `${cx},${cz}`;
      needed.add(key);
      const dist = Math.hypot(dx, dz);
      const lod = dist < 2 ? NEAR_LOD : FAR_LOD;
      const existing = chunks.current.get(key);
      if (existing && existing.lod !== lod) { scene.remove(existing.mesh); existing.mesh.geometry.dispose(); (existing.mesh.material as THREE.Material).dispose(); chunks.current.delete(key); }
      if (!chunks.current.has(key)) {
        const mesh = buildChunk(cx, cz, SIZE, lod);
        scene.add(mesh);
        chunks.current.set(key, { mesh, lod });
      }
    }
    for (const [key, c] of chunks.current) if (!needed.has(key)) { scene.remove(c.mesh); c.mesh.geometry.dispose(); (c.mesh.material as THREE.Material).dispose(); chunks.current.delete(key); }
  });
  useEffect(() => () => { for (const c of chunks.current.values()) { c.mesh.geometry.dispose(); (c.mesh.material as THREE.Material).dispose(); } }, []);
  return null;
}

