export default function forecast(input: { days: number; baseline: number }): { day: number; value: number }[] {
  const out: { day: number; value: number }[] = [];
  for (let d = 0; d < input.days; d++) {
    let v = input.baseline;
    for (let i = 0; i < 1_000_000; i++) v = (v + Math.sin(i)) * 1.0001;
    out.push({ day: d, value: v });
  }
  return out;
}

