import { Server, Socket } from 'socket.io';

type Pos = { x: number; y: number };
const buffer = new Map<string, Map<string, Pos>>();

export function attachCursorNamespace(io: Server) {
  const ns = io.of('/cursors');
  ns.on('connection', (socket: Socket) => {
    const userId = (socket as any).data.userId as string;
    socket.on('cursor:join', (room: string) => { socket.join(room); });
    socket.on('cursor:move', (room: string, pos: Pos) => {
      let m = buffer.get(room); if (!m) { m = new Map(); buffer.set(room, m); }
      m.set(userId, pos);
    });
  });
  setInterval(() => {
    for (const [room, m] of buffer) {
      if (m.size === 0) continue;
      const payload = Array.from(m, ([uid, pos]) => ({ userId: uid, pos }));
      ns.to(room).emit('cursors:batch', payload);
      m.clear();
    }
  }, 33);
}

import { useEffect, useState } from 'react';
import { io } from 'socket.io-client';
export function useCursors(room: string, token: string) {
  const [cursors, setCursors] = useState<{ userId: string; pos: { x: number; y: number } }[]>([]);
  useEffect(() => {
    const socket = io('/cursors', { auth: { token } });
    socket.emit('cursor:join', room);
    socket.on('cursors:batch', (b: { userId: string; pos: { x: number; y: number } }[]) => setCursors(b));
    return () => { socket.disconnect(); };
  }, [room, token]);
  return cursors;
}

