const ROLE_PERMS: Record<string, string[]> = {
  admin: ['read','write','admin'],
  manager: ['read','write'],
  viewer: ['read']
};

export async function can(orgId: string, userId: string, action: 'read' | 'write' | 'admin', resource?: { type: string; id: string }): Promise<boolean> {
  if (resource) {
    const grant = await ResourceGrantModel.findOne({ orgId, userId, resourceType: resource.type, resourceId: resource.id }).lean();
    if (grant) return checkPermLevel(grant.permission, action);
  }
  const m = await MembershipModel.findOne({ orgId, userId }).lean();
  if (!m) return false;
  return ROLE_PERMS[m.role]?.includes(action) ?? false;
}

function checkPermLevel(granted: string, requested: string) {
  const level = ['read','write','admin'];
  return level.indexOf(granted) >= level.indexOf(requested);
}

import { AuditLogModel } from '../models/audit-log.model';
