type Executor = (details: unknown, actorId: string) => Promise<void>;
const registry: Record<string, Executor> = {
  'order.created': async (details, actorId) => { await orderService.place((details as { input: { userId: string; total: number } }).input); }
};

export async function replay(opts: { from?: Date; to?: Date; entity?: string; targetEnv: string }) {
  if (opts.targetEnv === 'production') throw new Error('Refuse to replay against production');
  const filter: Record<string, unknown> = {};
  if (opts.from || opts.to) filter.at = { ...(opts.from ? { $gte: opts.from } : {}), ...(opts.to ? { $lte: opts.to } : {}) };
  if (opts.entity) filter.action = new RegExp(`^${opts.entity}\\.`);
  const cursor = AuditLogModel.find(filter).sort({ at: 1 }).cursor();
  let processed = 0;
  for await (const log of cursor) {
    const exec = registry[log.action];
    if (!exec) continue;
    await exec(log.details, String(log.actorId));
    processed++;
  }
  return { processed };
}

