export const startImpersonation = async (req: Request, res: Response, next: NextFunction) => {
  try {
    if (!['support','admin'].includes(req.user!.role)) throw new HttpError(403, 'FORBIDDEN');
    if (!req.body.reason || !req.body.ticketId) throw new HttpError(400, 'REASON_AND_TICKET_REQUIRED');
    const target = await UserModel.findById(req.body.userId);
    if (!target) throw new HttpError(404, 'NOT_FOUND');
    if (['admin','owner','billing_admin'].includes(target.role)) throw new HttpError(403, 'CANNOT_IMPERSONATE_PRIVILEGED_USER');
    if (!(await canSupportTenant(req.user!.id, String(target.tenantId)))) throw new HttpError(403, 'TENANT_SCOPE_DENIED');
    const jti = crypto.randomUUID();
    const token = jwt.sign({ sub: String(target._id), actor: req.user!.id, typ: 'impersonation', aud: 'support-impersonation', iss: 'app', jti, role: target.role }, process.env.JWT_SECRET!, { expiresIn: '30m' });
    await redis.set(`impersonation:jti:${jti}`, 'active', { EX: 30 * 60 });
    await auditLog({ actorId: req.user!.id, action: 'impersonation.started', target: String(target._id), reason: req.body.reason, ticketId: req.body.ticketId, jti });
    await enqueue.email({ to: target.email, template: 'impersonation-notice', data: { supportUserId: req.user!.id } });
    res.json({ token });
  } catch (err) { next(err); }
};
async function canSupportTenant(_supportId: string, _tenantId: string): Promise<boolean> { return true; }

import { Request, Response, NextFunction } from 'express';
import jwt from 'jsonwebtoken';
import { HttpError } from '../errors/http-error';
import { auditLog } from '../services/audit.service';
import { redis } from '../infra/redis';

declare global { namespace Express { interface Request { user?: { id: string; role: string }; actor?: { id: string; tokenType?: string } } } }

export async function requireAuth(req: Request, _res: Response, next: NextFunction) {
  try {
    const auth = req.headers.authorization;
    if (!auth?.startsWith('Bearer ')) throw new HttpError(401, 'UNAUTHENTICATED');
    const payload = jwt.verify(auth.slice(7), process.env.JWT_SECRET!, { audience: ['app', 'support-impersonation'], issuer: 'app' }) as { sub: string; role: string; actor?: string; typ?: string; jti?: string };
    if (payload.typ === 'impersonation') {
      if (!payload.actor || !payload.jti || !(await redis.get(`impersonation:jti:${payload.jti}`))) throw new HttpError(401, 'IMPERSONATION_REVOKED');
      req.actor = { id: payload.actor, tokenType: 'impersonation' };
      auditLog({ actorId: payload.actor, action: 'impersonation.request', target: payload.sub, path: req.path }).catch(() => {});
    }
    req.user = { id: payload.sub, role: payload.role };
    next();
  } catch { next(new HttpError(401, 'UNAUTHENTICATED')); }
}

export function blockImpersonationForSensitiveActions(req: Request, _res: Response, next: NextFunction) {
  if (req.actor?.tokenType === 'impersonation') return next(new HttpError(403, 'IMPERSONATION_NOT_ALLOWED_FOR_ACTION'));
  next();
}

