import { createContext, useContext, useState, useCallback, useMemo, ReactNode } from 'react';

const CountStateContext = createContext(0);
const CountActionsContext = createContext<{ inc: () => void; reset: () => void } | null>(null);

export function CountProvider({ children }: { children: ReactNode }) {
  const [count, setCount] = useState(0);
  const inc = useCallback(() => setCount(c => c + 1), []);
  const reset = useCallback(() => setCount(0), []);
  const actions = useMemo(() => ({ inc, reset }), [inc, reset]);
  return (
    <CountStateContext.Provider value={count}>
      <CountActionsContext.Provider value={actions}>{children}</CountActionsContext.Provider>
    </CountStateContext.Provider>
  );
}

export const useCount = () => useContext(CountStateContext);
export const useCountActions = () => { const c = useContext(CountActionsContext); if (!c) throw new Error('CountProvider missing'); return c; };

import { useEffect, useState } from 'react';
