type Item = { _id: string; text: string; createdAt: string; severity: number };

export function Queue({ token }: { token: string }) {
  const [items, setItems] = useState<Item[]>([]);
  useEffect(() => {
    fetch('/api/moderation').then(r => r.json()).then(setItems);
    const socket = io('/moderation', { auth: { token } });
    socket.on('item:added', (i: Item) => setItems(prev => [...prev, i].sort((a, b) => b.severity - a.severity).slice(0, 200)));
    socket.on('item:updated', (i: Item) => setItems(prev => prev.map(x => x._id === i._id ? i : x).sort((a, b) => b.severity - a.severity)));
    socket.on('item:removed', ({ _id }: { _id: string }) => setItems(prev => prev.filter(x => x._id !== _id)));
    return () => { socket.disconnect(); };
  }, [token]);
  return <ul>{items.map(i => <li key={i._id}>{i.text}</li>)}</ul>;
}

export function describeError(err: unknown): string {
  const parts: string[] = [];
  let current: unknown = err;
  while (current) {
    if (current instanceof Error) {
      parts.push(`${current.name}: ${current.message}`);
      current = (current as Error & { cause?: unknown }).cause;
    } else {
      parts.push(String(current));
      break;
    }
  }
  return parts.join(' caused by ');
}

