import { Canvas, useFrame } from '@react-three/fiber';
import { OrbitControls } from '@react-three/drei';
import { useRef, useState } from 'react';
import * as THREE from 'three';

type Body = { name: string; r: number; visR: number; orbit: number; visOrbit: number; color: string; speed: number };
const BODIES: Body[] = [
  { name: 'Sun', r: 1, visR: 1, orbit: 0, visOrbit: 0, color: '#fff200', speed: 0 },
  { name: 'Earth', r: 0.01, visR: 0.3, orbit: 1.5, visOrbit: 3, color: '#5b8def', speed: 0.5 },
  { name: 'Mars', r: 0.005, visR: 0.2, orbit: 2.3, visOrbit: 5, color: '#d96b6b', speed: 0.3 }
];

function Body({ body, mix, t }: { body: Body; mix: number; t: number }) {
  const ref = useRef<THREE.Mesh>(null);
  useFrame(() => {
    if (!ref.current) return;
    const r = body.r * (1 - mix) + body.visR * mix;
    ref.current.scale.set(r, r, r);
    const o = body.orbit * (1 - mix) + body.visOrbit * mix;
    const angle = t * body.speed;
    ref.current.position.set(Math.cos(angle) * o, 0, Math.sin(angle) * o);
  });
  return <mesh ref={ref}><sphereGeometry args={[1, 16, 16]} /><meshStandardMaterial color={body.color} emissive={body.name === 'Sun' ? body.color : '#000'} emissiveIntensity={body.name === 'Sun' ? 1 : 0} /></mesh>;
}

function Orbits({ mix }: { mix: number }) {
  return <>{BODIES.filter(b => b.orbit > 0).map(b => {
    const r = b.orbit * (1 - mix) + b.visOrbit * mix;
    const points = Array.from({ length: 64 }, (_, i) => new THREE.Vector3(Math.cos(i / 64 * Math.PI * 2) * r, 0, Math.sin(i / 64 * Math.PI * 2) * r));
    const geom = new THREE.BufferGeometry().setFromPoints(points);
    return <lineLoop key={b.name} geometry={geom}><lineBasicMaterial color="#888" /></lineLoop>;
  })}</>;
}

export function Solar() {
  const [visual, setVisual] = useState(true);
  const mixRef = useRef(1);
  const tRef = useRef(0);
  return (
    <div className="w-full h-screen relative">
      <button onClick={() => setVisual(v => !v)} className="absolute top-2 left-2 z-10 px-3 py-1 bg-white rounded">Toggle scale</button>
      <Canvas camera={{ position: [0, 5, 10] }}>
        <ambientLight intensity={0.5} />
        <pointLight intensity={1} />
        <FrameDriver visual={visual} mixRef={mixRef} tRef={tRef} />
        <Orbits mix={mixRef.current} />
        {BODIES.map(b => <Body key={b.name} body={b} mix={mixRef.current} t={tRef.current} />)}
        <OrbitControls />
      </Canvas>
    </div>
  );
}

function FrameDriver({ visual, mixRef, tRef }: { visual: boolean; mixRef: { current: number }; tRef: { current: number } }) {
  useFrame((_state, delta) => {
    mixRef.current += ((visual ? 1 : 0) - mixRef.current) * 0.05;
    tRef.current += delta;
  });
  return null;
}

