function hashToken(t: string) { return crypto.createHash('sha256').update(t).digest('hex'); }

export const createShare = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const token = crypto.randomBytes(24).toString('base64url');
    await ShareLinkModel.create({ docId: req.params.docId, tokenHash: hashToken(token), role: req.body.role, expiresAt: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000), createdBy: req.user!.id });
