    const link = await ShareLinkModel.findOne({ tokenHash: hashToken(token), expiresAt: { $gt: new Date() } });
    if (!link) throw new HttpError(404, 'INVALID_OR_EXPIRED');
    const jwtToken = jwt.sign({ docId: String(link.docId), role: link.role, anon: true }, process.env.JWT_SECRET!, { expiresIn: '4h' });
