};

import { Server, Socket } from 'socket.io';
import jwt from 'jsonwebtoken';
import { ShareLinkModel } from '../models/share-link.model';

export function attachDocPresenceNamespace(io: Server) {
  const ns = io.of('/doc-presence');
  ns.use(async (socket: Socket, next) => {
    try {
      const token = socket.handshake.auth?.token;
      const payload = jwt.verify(token, process.env.JWT_SECRET!) as { docId: string; role: 'view' | 'comment' | 'edit'; anon?: boolean; linkId?: string; sub?: string };
      if (payload.linkId) {
        const active = await ShareLinkModel.exists({ _id: payload.linkId, docId: payload.docId, role: payload.role, expiresAt: { $gt: new Date() } });
        if (!active) return next(new Error('share_expired'));
      }
      (socket.data as any).docId = payload.docId;
      (socket.data as any).role = payload.role;
      (socket.data as any).userId = payload.sub ?? `anon:${socket.id}`;
      next();
    } catch { next(new Error('unauthorized')); }
  });
  ns.on('connection', (socket: Socket) => {
    const { docId, role, userId } = socket.data as any;
    socket.join(`doc:${docId}`);
    socket.to(`doc:${docId}`).emit('peer:joined', { userId, role });
    socket.on('disconnect', () => socket.to(`doc:${docId}`).emit('peer:left', { userId }));
  });
}

import { z, ZodSchema } from 'zod';
import { redis } from '../infra/redis';

const schema = z.object({
  rateLimit: z.number().int().min(1).max(10_000).default(100),
  cacheTtl: z.number().int().min(0).default(60)
});

let cache: z.infer<typeof schema> | null = null;
let cacheAt = 0;
const TTL_MS = 5000;

const sub = redis.duplicate();
sub.subscribe('config:invalidate', () => { cache = null; });

export async function getConfig() {
  if (cache && Date.now() - cacheAt < TTL_MS) return cache;
  const raw = await redis.hGetAll('config');
  const parsed = schema.safeParse({ rateLimit: Number(raw.rateLimit), cacheTtl: Number(raw.cacheTtl) });
  cache = parsed.success ? parsed.data : schema.parse({});
  cacheAt = Date.now();
  return cache;
}

export async function setConfigValue(key: keyof z.infer<typeof schema>, value: unknown) {
  await redis.hSet('config', key, String(value));
  await redis.publish('config:invalidate', key);
}
